import React, { useState } from "react";
import axios from "axios";

function App() {
  const [file, setFile] = useState(null);
  const [mask, setMask] = useState(null);
  const [outlined, setOutlined] = useState(null);

  const handleUpload = async () => {
    const formData = new FormData();
    formData.append("file", file);

    const response = await axios.post(
      "http://localhost:5000/predict",
      formData
    );

    setMask("data:image/png;base64," + response.data.mask);
    setOutlined("data:image/png;base64," + response.data.outlined);
  };

  return (
    <div style={{ textAlign: "center", marginTop: "40px" }}>
      <h2>Brain Tumor Segmentation</h2>

      <input type="file" onChange={(e) => setFile(e.target.files[0])} />
      <br /><br />
      <button onClick={handleUpload}>Predict</button>

      <div style={{ display: "flex", justifyContent: "center", gap: "40px", marginTop: "40px" }}>
        {mask && (
          <div>
            <h3>Tumor Mask</h3>
            <img src={mask} alt="mask" />
          </div>
        )}

        {outlined && (
          <div>
            <h3>Outlined Tumor</h3>
            <img src={outlined} alt="outlined" />
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
